import React from 'react';
// Icons import karanyachi hi sarvat safe padhat ahe
import { FiPackage, FiTruck, FiBox, FiGlobe, FiBriefcase, FiMapPin } from 'react-icons/fi';

const ServiceCard = ({ icon: Icon, title, desc, color }) => (
  <div style={{
    flex: '1', minWidth: '280px', margin: '15px', padding: '30px',
    backgroundColor: 'rgba(255, 255, 255, 0.9)', borderRadius: '20px', textAlign: 'center',
    boxShadow: '0 10px 30px rgba(0,0,0,0.1)', borderTop: `6px solid ${color}`,
    backdropFilter: 'blur(8px)', transition: '0.3s'
  }}>
    <div style={{ fontSize: '3rem', color: color, marginBottom: '15px' }}><Icon /></div>
    <h5 style={{ fontWeight: 'bold', color: '#333', textTransform: 'uppercase', fontSize: '1rem' }}>{title}</h5>
    <p style={{ color: '#666', fontSize: '0.85rem', lineHeight: '1.4' }}>{desc}</p>
    <button style={{ 
      backgroundColor: color, color: 'white', border: 'none', 
      padding: '10px 25px', borderRadius: '25px', fontWeight: 'bold', cursor: 'pointer' 
    }}>Select Service</button>
  </div>
);

const Home = () => {
  return (
    <div style={{ padding: '60px 20px' }}>
      <div style={{ textAlign: 'center', marginBottom: '50px' }}>
        <h1 style={{ fontSize: '3.5rem', fontWeight: '900', color: '#1a1a1a', letterSpacing: '-1px' }}>
          Apni Manzil <span style={{ color: '#0056b3' }}>Logistics</span>
        </h1>
        <p style={{ 
          fontSize: '1.2rem', color: '#0056b3', fontWeight: 'bold', 
          background: 'white', display: 'inline-block', padding: '10px 30px', 
          borderRadius: '50px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)' 
        }}>
          Smart Aggregator for MSMEs & Partners
        </p>
      </div>

      <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', maxWidth: '1300px', margin: '0 auto' }}>
        <ServiceCard icon={FiPackage} title="Courier Services" desc="Express Domestic & Hyper-local Delivery" color="#2ecc71" />
        <ServiceCard icon={FiTruck} title="Transport" desc="Full Truck Load & Part Load Capacity" color="#f1c40f" />
        <ServiceCard icon={FiBox} title="Packers & Movers" desc="Relocation Services with Safety Assurance" color="#f39c12" />
        <ServiceCard icon={FiGlobe} title="International" desc="Global Freight & Cross-border Logistics" color="#9b59b6" />
        <ServiceCard icon={FiBriefcase} title="Business MSME" desc="Dedicated Supply Chain for Small Businesses" color="#3498db" />
        <ServiceCard icon={FiMapPin} title="Live Tracking" desc="Real-time GPS Monitoring & AI Analytics" color="#e74c3c" />
      </div>
    </div>
  );
};

export default Home;
